/**
 * Broadcast mode for transactions
 */

enum class BroadcastMode {
    
    /**
     * Synchronous - returns after CheckTx
     */
    SYNC,
    /**
     * Asynchronous - returns immediately
     */
    ASYNC,
    /**
     * Block - waits until transaction is included in a block
     */
    BLOCK;
    companion object
}


/**
 * @suppress
 */
public object FfiConverterTypeBroadcastMode: FfiConverterRustBuffer<BroadcastMode> {
    override fun read(buf: ByteBuffer) = try {
        BroadcastMode.values()[buf.getInt() - 1]
    } catch (e: IndexOutOfBoundsException) {
        throw RuntimeException("invalid enum value, something is very wrong!!", e)
    }

    override fun allocationSize(value: BroadcastMode) = 4UL

    override fun write(value: BroadcastMode, buf: ByteBuffer) {
        buf.putInt(value.ordinal + 1)
    }
}







/**
 * Main error type for the mob library
 */
sealed class MobException(message: String): kotlin.Exception(message) {
        
    /**
     * RPC-related errors
     */
        class Rpc(message: String) : MobException(message)
        
    /**
     * Transaction-related errors
     */
        class Transaction(message: String) : MobException(message)
        
    /**
     * Signing-related errors
     */
        class Signing(message: String) : MobException(message)
        
    /**
     * Key derivation errors
     */
        class KeyDerivation(message: String) : MobException(message)
        
    /**
     * Address parsing/generation errors
     */
        class Address(message: String) : MobException(message)
        
    /**
     * Serialization/deserialization errors
     */
        class Serialization(message: String) : MobException(message)
        
    /**
     * Invalid input errors
     */
        class InvalidInput(message: String) : MobException(message)
        
    /**
     * Account-related errors
     */
        class Account(message: String) : MobException(message)
        
    /**
     * Network-related errors
     */
        class Network(message: String) : MobException(message)
        
    /**
     * Gas estimation errors
     */
        class GasEstimation(message: String) : MobException(message)
        
    /**
     * Insufficient funds
     */
        class InsufficientFunds(message: String) : MobException(message)
        
    /**
     * Timeout errors
     */
        class Timeout(message: String) : MobException(message)
        
    /**
     * Session expired errors
     */
        class SessionExpired(message: String) : MobException(message)
        
    /**
     * Generic error
     */
        class Generic(message: String) : MobException(message)
        

    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<MobException> {
        override fun lift(error_buf: RustBuffer.ByValue): MobException = FfiConverterTypeMobError.lift(error_buf)
    }
}

/**
 * @suppress
 */
public object FfiConverterTypeMobError : FfiConverterRustBuffer<MobException> {
    override fun read(buf: ByteBuffer): MobException {
        
            return when(buf.getInt()) {
            1 -> MobException.Rpc(FfiConverterString.read(buf))
            2 -> MobException.Transaction(FfiConverterString.read(buf))
            3 -> MobException.Signing(FfiConverterString.read(buf))
            4 -> MobException.KeyDerivation(FfiConverterString.read(buf))
            5 -> MobException.Address(FfiConverterString.read(buf))
            6 -> MobException.Serialization(FfiConverterString.read(buf))
            7 -> MobException.InvalidInput(FfiConverterString.read(buf))
            8 -> MobException.Account(FfiConverterString.read(buf))
            9 -> MobException.Network(FfiConverterString.read(buf))
            10 -> MobException.GasEstimation(FfiConverterString.read(buf))
            11 -> MobException.InsufficientFunds(FfiConverterString.read(buf))
            12 -> MobException.Timeout(FfiConverterString.read(buf))
            13 -> MobException.SessionExpired(FfiConverterString.read(buf))
            14 -> MobException.Generic(FfiConverterString.read(buf))
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
        
    }

    override fun allocationSize(value: MobException): ULong {
        return 4UL
    }

    override fun write(value: MobException, buf: ByteBuffer) {
        when(value) {
            is MobException.Rpc -> {
                buf.putInt(1)
                Unit
            }
            is MobException.Transaction -> {
                buf.putInt(2)
                Unit
            }
            is MobException.Signing -> {
                buf.putInt(3)
                Unit
            }
            is MobException.KeyDerivation -> {
                buf.putInt(4)
                Unit
            }
            is MobException.Address -> {
                buf.putInt(5)
                Unit
            }
            is MobException.Serialization -> {
                buf.putInt(6)
                Unit
            }
            is MobException.InvalidInput -> {
                buf.putInt(7)
                Unit
            }
            is MobException.Account -> {
                buf.putInt(8)
                Unit
            }
            is MobException.Network -> {
                buf.putInt(9)
                Unit
            }
            is MobException.GasEstimation -> {
                buf.putInt(10)
                Unit
            }
            is MobException.InsufficientFunds -> {
                buf.putInt(11)
                Unit
            }
            is MobException.Timeout -> {
                buf.putInt(12)
                Unit
            }
            is MobException.SessionExpired -> {
                buf.putInt(13)
                Unit
            }
            is MobException.Generic -> {
                buf.putInt(14)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }

}





